# Tool-based offloading: expose external memory as a tool the agent can call.
# The agent decides WHEN to retrieve — injecting memory on-demand rather than
# blindly pre-filling the context with all possible relevant information.

from openai import OpenAI
import json

client = OpenAI(api_key="...")

# Simulated memory store (replace with Qdrant / Zep / Graphiti)
MEMORY = {
    "database": "Postgres 16 with pgvector",
    "tech_lead": "Alice",
    "deadline": "December 15",
    "framework": "FastAPI on Python 3.12",
}

def recall_memory(query: str) -> str:
    """Simulated retrieval — returns relevant facts for the query."""
    matches = {k: v for k, v in MEMORY.items()
               if any(w in query.lower() for w in k.split("_"))}
    if not matches:
        return "No relevant memory found."
    return "\n".join(f"- {k}: {v}" for k, v in matches.items())

TOOLS = [{
    "type": "function",
    "function": {
        "name": "recall_memory",
        "description": "Retrieve facts from long-term memory relevant to a query.",
        "parameters": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "The question to retrieve memory for."}
            },
            "required": ["query"],
        },
    },
}]

def agent_turn(user_input: str) -> str:
    messages = [
        {"role": "system", "content": "You are a helpful assistant. Use recall_memory when you need facts."},
        {"role": "user",   "content": user_input},
    ]
    while True:
        resp = client.chat.completions.create(
            model="gpt-4o-mini", messages=messages, tools=TOOLS, tool_choice="auto"
        )
        msg = resp.choices[0].message
        if msg.tool_calls:
            messages.append(msg)
            for tc in msg.tool_calls:
                args = json.loads(tc.function.arguments)
                result = recall_memory(args["query"])
                messages.append({
                    "role": "tool", "tool_call_id": tc.id, "content": result
                })
        else:
            return msg.content

print(agent_turn("What database are we using and who leads the team?"))
